192		snapshot, err := sem.BuildProviderSnapshotWithOptions(ctx, repo, opts.Version, sem.ProviderSnapshotOptions{
193			NoNetwork: flags.NoNetwork,
194			Worktree:  flags.Worktree,
195		})
196		if err != nil {
197			return err
198		}
199		switch mode {
200		case "snapshot":
201			return sem.WriteSnapshotNDJSON(opts.Stdout, snapshot)
202		case "symbols":
203			return sem.WriteSymbolsNDJSON(opts.Stdout, snapshot)
204		case "edges":
205			return sem.WriteRelationsNDJSON(opts.Stdout, snapshot)
206		default:
207			return fmt.Errorf("unknown provider record mode %q", mode)
208		}
