package sem

import (
	"bufio"
	"os"
	"regexp"
	"strings"
)

// ignoreMatcher evaluates gitignore-style patterns against repository-relative,
// slash-separated file paths. It supports the subset of .gitignore semantics
// that callers such as the Entire CLI rely on for an --ignore-file: comment and
// blank lines, directory-only patterns (trailing "/"), root-anchored patterns
// (containing a "/"), basename patterns matched at any depth, "*"/"?" globs,
// "**" across directories, and "!" negation with last-match-wins.
type ignoreMatcher struct {
	rules []ignoreRule
}

type ignoreRule struct {
	re      *regexp.Regexp
	negate  bool
	dirOnly bool
}

// loadIgnoreFile reads gitignore-style patterns from path. A non-existent file
// yields a nil matcher and the os error so callers can decide whether the
// absence is worth surfacing; any other read error is returned as well.
func loadIgnoreFile(path string) (*ignoreMatcher, error) {
	file, err := os.Open(path)
	if err != nil {
		return nil, err
	}
	defer file.Close()

	matcher := &ignoreMatcher{}
	scanner := bufio.NewScanner(file)
	for scanner.Scan() {
		if rule, ok := compileIgnoreLine(scanner.Text()); ok {
			matcher.rules = append(matcher.rules, rule)
		}
	}
	if err := scanner.Err(); err != nil {
		return nil, err
	}
	return matcher, nil
}

// Match reports whether the given repository-relative slash path is ignored.
func (m *ignoreMatcher) Match(path string) bool {
	if m == nil || len(m.rules) == 0 {
		return false
	}

	// A path is ignored if it matches a rule directly or if any of its ancestor
	// directories is ignored. Build the directory prefixes once.
	segments := strings.Split(path, "/")
	dirs := make([]string, 0, len(segments)-1)
	for i := 1; i < len(segments); i++ {
		dirs = append(dirs, strings.Join(segments[:i], "/"))
	}

	ignored := false
	for _, rule := range m.rules {
		matched := false
		// Directory-only rules can only match via ancestor directories; other
		// rules also match the file path itself.
		if !rule.dirOnly && rule.re.MatchString(path) {
			matched = true
		}
		if !matched {
			for _, dir := range dirs {
				if rule.re.MatchString(dir) {
					matched = true
					break
				}
			}
		}
		if matched {
			ignored = !rule.negate
		}
	}
	return ignored
}

func compileIgnoreLine(line string) (ignoreRule, bool) {
	// Trailing whitespace is insignificant unless escaped; we don't support the
	// escape edge case, matching the practical patterns callers emit.
	trimmed := strings.TrimRight(line, " \t")
	if trimmed == "" || strings.HasPrefix(trimmed, "#") {
		return ignoreRule{}, false
	}

	rule := ignoreRule{}
	if strings.HasPrefix(trimmed, "!") {
		rule.negate = true
		trimmed = trimmed[1:]
	}
	if strings.HasSuffix(trimmed, "/") {
		rule.dirOnly = true
		trimmed = strings.TrimSuffix(trimmed, "/")
	}

	// A leading or internal "/" anchors the pattern to the ignore-file root.
	// Otherwise the pattern matches a basename at any depth.
	anchored := strings.Contains(trimmed, "/")
	trimmed = strings.TrimPrefix(trimmed, "/")
	if trimmed == "" {
		return ignoreRule{}, false
	}

	expr := "^" + globToRegex(trimmed) + "$"
	if !anchored {
		expr = "^(?:.*/)?" + globToRegex(trimmed) + "$"
	}
	re, err := regexp.Compile(expr)
	if err != nil {
		return ignoreRule{}, false
	}
	rule.re = re
	return rule, true
}

// globToRegex converts a gitignore glob into a regular expression body. "**"
// spans directory separators, while "*" and "?" stop at them.
func globToRegex(pattern string) string {
	var b strings.Builder
	for i := 0; i < len(pattern); i++ {
		switch {
		case strings.HasPrefix(pattern[i:], "**/"):
			b.WriteString("(?:.*/)?")
			i += 2
		case strings.HasPrefix(pattern[i:], "**"):
			b.WriteString(".*")
			i++
		case pattern[i] == '*':
			b.WriteString("[^/]*")
		case pattern[i] == '?':
			b.WriteString("[^/]")
		default:
			b.WriteString(regexp.QuoteMeta(string(pattern[i])))
		}
	}
	return b.String()
}

